`]}),(0,o.jsx)(e.p,{children:"Careful, just because someone doesn\u2019t want to open the door to their heart for you doesn\u2019t mean they\u2019re a bad person. Remember, we are all free to do what we want with our lives. Just as you are free, so is the other person, although I know some people don't understand emotional responsibility. That's why they may be very interested at first, but then lose that interest. It\u2019s okay, just breathe, try as hard as you can, and if they don\u2019t open the door, leave it closed forever."}),(0,o.jsx)(e.p,{children:"So, for your own sake, try as hard as you can. If you see there's no opportunity, close that door for good. If possible, throw away the key into infinity, where you can never find it again. Sometimes we trap ourselves by focusing on just one person, but the truth is, you just need to step into the world. There are far more people out there than you can imagine, people who will be willing to let you in. When you find the right one, take good care of them, with lots of love, and you'll see that after the storm comes the calm."})]})}function j(t={}){let{wrapper:e}=t.components||{};return e?(0,o.jsx)(e,Object.assign({},t,{children:(0,o.jsx)(u,t)})):u(t)}var x=j;function y(t,e){throw new Error("Expected "+(e?"component":"object")+" `"+t+"` to be defined: you likely forgot to import, pass, or provide it.")}return v(_);})();
